import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface HourlyTrend {
  hour: string;
  speed: number;
}

interface WindData {
  location: string;
  currentWind: {
    speed: number;
    direction: string;
    gust: number;
  };
  hourlyTrend: HourlyTrend[];
}

export default function Widget() {
  const windData = response.data as WindData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#0D47A1' }} elevation={2}>
      <CardContent sx={{ p: 2.5, color: '#FFFFFF' }}>
        <Stack spacing={1.5}>
          <Box>
            <Typography variant="body2" color="inherit">
              {windData.location}
            </Typography>
            <Typography variant="h4" fontWeight={600} sx={{ mt: 0.5 }}>
              {windData.currentWind.speed} mph
            </Typography>
            <Typography variant="body2" sx={{ mb: 1 }}>
              Wind Direction: {windData.currentWind.direction}, Gusts up to {windData.currentWind.gust} mph
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: windData.hourlyTrend.map((trend) => trend.speed),
                  color: '#FFC107',
                  curve: 'natural',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: windData.hourlyTrend.map((trend) => trend.hour),
                  id: 'hours',
                },
              ]}
              yAxis={[{ id: 'speed' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="hours"
                tickLabelStyle={{ fontSize: 10, fill: '#FFFFFF' }}
              />
              <ChartsYAxis
                axisId="speed"
                tickLabelStyle={{ fontSize: 10, fill: '#FFFFFF' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
